function sanitizeInput(text) {
    const div = document.createElement('div');
    div.textContent = text;
    let cleanText = div.innerHTML;
    // Remover caracteres de control o scripts maliciosos extra
    return cleanText.replace(/<[^>]*>?/gm, '').trim();
}

